// T173 QueryExecutionEngine — three-layer security gate
// Layer order is MANDATORY AND IMMUTABLE
constructor(
  @Inject(DATABASE_SERVICE) private db: IDatabaseService,
  @Inject('F422') private rls: IRowLevelSecurityService,   // PLATFORM-ONLY
  @Inject('F423') private piiMask: IPIIMaskingService,      // PLATFORM-ONLY
) {
  // T187 is INLINE — no @Inject, no F426
  this.quotaManager = new QuotaManager(config);
}

async executeQuery(query: Record<string, unknown>): Promise<DataProcessResult<unknown>> {
  // Layer 1: T187 inline quota check (INLINE — never injected)
  const quota = await this.quotaManager.check(tenantId);
  if (!quota.isSuccess) {
    await this.queue.enqueue('QueryFailed', { reason: 'quota_exceeded' });
    return DataProcessResult.failure('QUOTA_EXCEEDED', 'Quota limit reached');
  }
  // Layer 2: F422 RLS (PLATFORM-ONLY — canBeDisabled: false)
  const rlsResult = await this.rls.apply(tenantId, query);
  if (!rlsResult.isSuccess) {
    await this.queue.enqueue('QueryFailed', { reason: 'rls_denied' });
    return DataProcessResult.failure('RLS_DENIED', 'Row-level security denied');
  }
  // Layer 3: F423 PII masking BEFORE serialization (PLATFORM-ONLY)
  const masked = await this.piiMask.mask(results);
  if (!masked.isSuccess) {
    await this.queue.enqueue('QueryFailed', { reason: 'masking_error' });
    return DataProcessResult.failure('MASKING_ERROR', 'PII masking failed');
  }
  await this.quotaManager.recordUsage(tenantId); // AFTER successful query
  return DataProcessResult.success(masked.data);
}
